const fs = require('fs');
const path = require('path');
const baseDir = '/home/node/n8n-local-files';

function getFiles(dir, allFiles = []) {
  if (!fs.existsSync(dir)) return allFiles;
  const files = fs.readdirSync(dir);
  for (const file of files) {
    const name = path.join(dir, file);
    if (fs.statSync(name).isDirectory()) {
      getFiles(name, allFiles);
    } else {
      const relativePath = path.relative(baseDir, name);
      const stats = fs.statSync(name);
      if (['.xlsx', '.pdf', '.png'].includes(path.extname(file).toLowerCase())) {
        allFiles.push({
          name: file,
          path: relativePath,
          extension: path.extname(file).slice(1).toUpperCase(),
          size: (stats.size / 1024).toFixed(1) + ' KB',
          mtime: stats.mtime
        });
      }
    }
  }
  return allFiles;
}

const fileList = getFiles(baseDir);
fileList.sort((a, b) => b.mtime - a.mtime);

return { files: fileList };

